class TokenService:
    def __init__(self, private_key: RSAPrivateKey) -> None:
        self._key = private_key

    def issue(self, subject: str, scopes: list[str]) -> str:
        payload = {"sub": subject, "scopes": scopes, "iat": now(), "exp": now() + ACCESS_TTL}
        return jwt.encode(payload, self._key, algorithm="RS256")
